import random, math

points = [(random.uniform(0,5), random.uniform(0,5)) for _ in range(20)] + \
         [(random.uniform(5,10), random.uniform(5,10)) for _ in range(20)]

centroids = [points[0], points[20]]

def distance(a, b):
    return math.sqrt((a[0]-b[0])**2 + (a[1]-b[1])**2)

for _ in range(10):
    clusters = [[], []]
    for p in points:
        nearest = min(range(2), key=lambda i: distance(p, centroids[i]))
        clusters[nearest].append(p)
    for i in range(2):
        if clusters[i]:
            centroids[i] = (sum(p[0] for p in clusters[i])/len(clusters[i]),
                           sum(p[1] for p in clusters[i])/len(clusters[i]))

print('Final centroids:', centroids)
print('Cluster sizes:', len(clusters[0]), len(clusters[1]))

