def merge_sort(arr):
    if len(arr) <= 1:
        return arr
    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])
    return merge(left, right)

def merge(left, right):
    result = []
    i = j = 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1
    result.extend(left[i:])
    result.extend(right[j:])
    return result

test = [38, 27, 43, 3, 9, 82, 10]
print(merge_sort(test))

from flask import Flask, jsonify, request
app = Flask(__name__)

items = [{'id': 1, 'name': 'Laptop'}, {'id': 2, 'name': 'Phone'}]

@app.route('/items', methods=['GET'])
def get_items():
    return jsonify(items)

@app.route('/items', methods=['POST'])
def add_item():
    data = request.json
    new_item = {'id': len(items)+1, 'name': data['name']}
    items.append(new_item)
    return jsonify(new_item), 201

if __name__ == '__main__':
    app.run(debug=True)

def series_resistance(*resistors):
    return sum(resistors)

def parallel_resistance(*resistors):
    return 1 / sum(1/r for r in resistors)

def analyze_circuit(voltage, resistance):
    current = voltage / resistance
    power = voltage * current
    return {'voltage': voltage, 'resistance': resistance,
            'current': round(current, 4), 'power': round(power, 4)}

# Example: 3 resistors in parallel, then in series with one more
r_parallel = parallel_resistance(100, 200, 300)
r_total = series_resistance(r_parallel, 50)
circuit = analyze_circuit(12, r_total)
print(circuit)

def electron_config(atomic_number):
    orbitals = [
        ('1s', 2), ('2s', 2), ('2p', 6), ('3s', 2), ('3p', 6),
        ('4s', 2), ('3d', 10), ('4p', 6), ('5s', 2), ('4d', 10),
        ('5p', 6), ('6s', 2)
    ]
    config = []
    remaining = atomic_number
    for orbital, max_e in orbitals:
        if remaining <= 0:
            break
        electrons = min(remaining, max_e)
        config.append(f'{orbital}^{electrons}')
        remaining -= electrons
    return ' '.join(config)

for name, z in [('H', 1), ('C', 6), ('Na', 11), ('Fe', 26)]:
    print(f'{name}: {electron_config(z)}')

data = {
    'control': [23, 25, 24, 26, 22, 25, 23, 24],
    'experimental': [35, 38, 33, 40, 36, 37, 34, 39]
}

def statistics(values):
    n = len(values)
    mean = sum(values) / n
    variance = sum((x - mean)**2 for x in values) / (n-1)
    std_dev = variance**0.5
    sorted_v = sorted(values)
    median = (sorted_v[n//2-1] + sorted_v[n//2]) / 2 if n%2 == 0 else sorted_v[n//2]
    return {'mean': round(mean,2), 'std_dev': round(std_dev,2), 'median': round(median,2)}

for group, values in data.items():
    print(f'{group}: {statistics(values)}')
